#!/usr/bin/env bash
# Generated by OrchestKit Claude Plugin — Created: 2026-04-27
# /ork:dev boot — spin up portless + emulate + dev server + agent-browser session.
# Idempotent. Writes state to .claude/state/dev-stack.json.
# Exit codes: 0 = booted (or already live), 1 = aborted (missing prereq).

set -euo pipefail

PROJECT_DIR="${CLAUDE_PROJECT_DIR:-$(pwd)}"
STATE_DIR="${PROJECT_DIR}/.claude/state"
STATE_FILE="${STATE_DIR}/dev-stack.json"
LOG_FILE="${STATE_DIR}/dev.log"

# ── 0. Detect package manager ───────────────────────────────────────────────
detect_pkg_mgr() {
  if [[ -f "${PROJECT_DIR}/pnpm-lock.yaml" ]]; then echo "pnpm"; return; fi
  if [[ -f "${PROJECT_DIR}/yarn.lock"     ]]; then echo "yarn"; return; fi
  if [[ -f "${PROJECT_DIR}/bun.lockb"     ]]; then echo "bun";  return; fi
  echo "npm"
}

# ── 1. Resolve subdomain from branch ────────────────────────────────────────
slug_branch() {
  local b
  b=$(git -C "${PROJECT_DIR}" rev-parse --abbrev-ref HEAD 2>/dev/null || echo "dev")
  [[ "$b" == "HEAD" ]] && b="dev"
  echo "$b" | tr '[:upper:]' '[:lower:]' | tr '/' '-' | tr -cd 'a-z0-9-' | cut -c1-63
}

# ── Prereq check (all-or-nothing) ───────────────────────────────────────────
require() {
  local cmd="$1"
  local install="$2"
  if ! command -v "$cmd" >/dev/null 2>&1; then
    echo "✗ ${cmd} not found.   Install: ${install}" >&2
    return 1
  fi
  echo "✓ ${cmd}     found"
}

main() {
  mkdir -p "${STATE_DIR}"

  # CI escape hatch
  if [[ "${CI:-}" == "1" || "${CI:-}" == "true" ]]; then
    echo "ork:dev — CI=1, skipping boot." >&2
    exit 0
  fi

  echo "ork:dev — checking prerequisites…" >&2
  local missing=0
  require portless      "npm i -g portless"      || missing=1
  require emulate       "npm i -g emulate"       || missing=1
  require agent-browser "npm i -g agent-browser" || missing=1
  if [[ $missing -ne 0 ]]; then
    echo "" >&2
    echo "Skipping boot — install missing tools and re-run." >&2
    exit 1
  fi

  # Idempotent: if state file exists and at least one PID is live, no-op.
  if [[ -f "${STATE_FILE}" ]]; then
    if "${BASH_SOURCE%/*}/status.sh" --quiet 2>/dev/null; then
      echo "ork:dev — already running. Run scripts/stop.sh to tear down." >&2
      exit 0
    fi
    echo "ork:dev — state file exists but stack is dead. Cleaning up…" >&2
    rm -f "${STATE_FILE}"
  fi

  local pkg_mgr; pkg_mgr=$(detect_pkg_mgr)
  local slug;    slug=$(slug_branch)
  local sub="${slug}.localhost"
  local base_url="https://${sub}"

  echo "[1] subdomain  ${sub}" >&2

  # 2. portless start
  echo "[2] portless start --domain ${sub} --tls --lan --background" >&2
  portless start --domain "${sub}" --tls --lan --background >>"${LOG_FILE}" 2>&1 || {
    echo "✗ portless start failed (see ${LOG_FILE})" >&2
    exit 1
  }
  local portless_pid
  portless_pid=$(pgrep -f "portless.*${sub}" | head -1 || echo "")

  # 3-4. emulate-seed + emulate up (only if config present)
  local emulators="[]"
  if [[ -f "${PROJECT_DIR}/emulate.config.yaml" ]]; then
    echo "[3] emulate.config.yaml found — emulate up" >&2
    emulate up --config "${PROJECT_DIR}/emulate.config.yaml" >>"${LOG_FILE}" 2>&1 &
    emulate_pid=$!
    emulators=$(python3 -c "
import yaml, json
with open('${PROJECT_DIR}/emulate.config.yaml') as f:
    cfg = yaml.safe_load(f) or {}
print(json.dumps(list((cfg.get('services') or {}).keys())))
" 2>/dev/null || echo "[]")
  else
    echo "[3-4] no emulate.config.yaml — skipping emulators (run /ork:emulate-seed --auto first)" >&2
    emulate_pid=""
  fi

  # 5. dev server
  echo "[5] ${pkg_mgr} dev (background)" >&2
  ("${pkg_mgr}" run dev >>"${LOG_FILE}" 2>&1) &
  local dev_pid=$!

  # 6. wait-on
  echo "[6] wait-on ${base_url}" >&2
  npx --yes wait-on --httpTimeout 30000 --tlsCheck false "${base_url}" 2>>"${LOG_FILE}" || {
    echo "✗ ${base_url} did not become reachable in 30s" >&2
    kill "${dev_pid}" 2>/dev/null || true
    exit 1
  }

  # 7. agent-browser
  echo "[7] agent-browser session start --name ${slug}" >&2
  agent-browser session start --name "${slug}" >>"${LOG_FILE}" 2>&1 || true
  agent-browser open "${base_url}" >>"${LOG_FILE}" 2>&1 || true

  # 8. atomic state write
  python3 - <<EOF
import json, os
state = {
  "bootedAt":  "$(date -u +%Y-%m-%dT%H:%M:%SZ)",
  "branch":    "$(git -C '${PROJECT_DIR}' rev-parse --abbrev-ref HEAD 2>/dev/null || echo dev)",
  "subdomain": "${sub}",
  "baseUrl":   "${base_url}",
  "processes": {
    "portless":    {"pid": ${portless_pid:-0}, "command": "portless start --domain ${sub} --tls --lan --background"},
    "emulate":     {"pid": ${emulate_pid:-0}, "command": "emulate up"} if ${emulate_pid:-0} != 0 else None,
    "devServer":   {"pid": ${dev_pid}, "command": "${pkg_mgr} run dev"},
    "agentBrowser":{"sessionName": "${slug}"},
  },
  "emulators": ${emulators},
}
state["processes"] = {k: v for k, v in state["processes"].items() if v is not None}
tmp = "${STATE_FILE}.tmp"
with open(tmp, "w") as f:
    json.dump(state, f, indent=2)
os.replace(tmp, "${STATE_FILE}")
EOF

  # 9. summary
  echo "" >&2
  echo "ork:dev — booted" >&2
  echo "  ✓ portless     ${base_url}" >&2
  [[ -n "${emulate_pid}" ]] && echo "  ✓ emulate      $(echo ${emulators} | python3 -c 'import sys,json; print(", ".join(json.load(sys.stdin)) or "none")') " >&2
  echo "  ✓ ${pkg_mgr} dev    pid ${dev_pid}" >&2
  echo "  ✓ agent-browser  session \"${slug}\"" >&2
  echo "" >&2
  echo "Open ${base_url} or run /ork:expect" >&2
}

main "$@"
